import{_ as t,o,c as a,a2 as r}from"./chunks/framework.ChXBHUFc.js";const g=JSON.parse('{"title":"Web Bluetooth controller (orientation visualizer)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/controller.md","filePath":"guide/controller.md","lastUpdated":1782669562000}'),s={name:"guide/controller.md"};function i(l,e,n,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="web-bluetooth-controller-orientation-visualizer" tabindex="-1">Web Bluetooth controller (orientation visualizer) <a class="header-anchor" href="#web-bluetooth-controller-orientation-visualizer" aria-label="Permalink to &quot;Web Bluetooth controller (orientation visualizer)&quot;">​</a></h1><p><a href="../controller/" target="_blank" rel="noreferrer"><strong>▶ Open the live controller</strong></a> — runs in the browser, no install (Chromium-based browsers only).</p><p>A static page (<code>docs/public/controller/index.html</code>) that connects to the Triki token straight from the browser via the <strong>Web Bluetooth API</strong>, streams the IMU, and drives a live 3D model tracking the token&#39;s orientation. No backend and no build step — it is published with this site and also runs locally.</p><blockquote><p>The page is a thin UI over the <a href="./library"><code>triki-controller</code></a> npm package: all of the BLE, frame parsing and Madgwick fusion live in the package, loaded at runtime from a CDN (<code>https://esm.sh/triki-controller</code>). The page itself only renders the model, readouts and controls. (Loading from a CDN means the page needs network access on first load; the package is tiny and gets cached.)</p></blockquote><blockquote><p>OPSEC: the page stores <strong>no device identifiers</strong> — the browser&#39;s device picker selects the token at runtime. Keep the serial / MAC / host UUID out of any tracked file; this doc uses <code>&lt;serial&gt;</code> / <code>XX:XX:XX:XX:XX:XX</code> placeholders.</p></blockquote><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><ul><li>Connects to the Nordic UART Service, subscribes to TX, sends the IMU start command.</li><li>Decodes the 14-byte frames (same math as <code>tools/ble_imu_stream.py</code>).</li><li>Fuses gyro + accel with a 6-axis <strong>Madgwick AHRS</strong> filter into an orientation quaternion; drives a live 3D glTF model (rendered with the <code>&lt;model-viewer&gt;</code> web component) plus a roll/pitch/yaw readout.</li><li>Shows per-axis accel (g) and gyro (°/s) with bar indicators and a live sample rate.</li><li>Cycles the IMU sample rate (0.25× … 4×) and lets you swap the displayed 3D model.</li><li>Toggles the green LED (control register <code>0x0004</code>).</li></ul><h2 id="browser-support" tabindex="-1">Browser support <a class="header-anchor" href="#browser-support" aria-label="Permalink to &quot;Browser support&quot;">​</a></h2><ul><li>Works in desktop <strong>Chrome / Edge / Opera</strong> (Chromium). <strong>Safari and Firefox do not implement Web Bluetooth.</strong></li><li>On macOS, grant the browser Bluetooth access in <strong>System Settings → Privacy &amp; Security → Bluetooth</strong>.</li><li>Requires a <strong>secure context</strong>: <code>https://</code> or <code>http://localhost</code>. Opening the file directly as <code>file://</code> will <strong>not</strong> work.</li></ul><h2 id="run-it" tabindex="-1">Run it <a class="header-anchor" href="#run-it" aria-label="Permalink to &quot;Run it&quot;">​</a></h2><p><strong>Published (recommended):</strong> open the <a href="../controller/" target="_blank" rel="noreferrer">live controller</a> — GitHub Pages serves it over HTTPS, which is a secure context, so Web Bluetooth works directly, no local server needed.</p><p><strong>Locally:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/public/controller</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http.server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8000</span></span></code></pre></div><p>Then open <a href="http://localhost:8000" target="_blank" rel="noreferrer">http://localhost:8000</a> in Chrome. <code>localhost</code> counts as a secure context, so Web Bluetooth is enabled with no certificate setup.</p><blockquote><p>Only one BLE central can hold the token at a time — close any running bleak script (<code>ble_nus.py</code>, <code>ble_dump.py</code>, <code>ble_imu_stream.py</code>) first.</p></blockquote><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><ol><li>Click <strong>Connect</strong> and pick <code>TRIKI &lt;serial&gt;</code> in the chooser.</li><li>The page sends the start command automatically; status turns to <em>streaming</em> and the rate settles around <strong>104 Hz</strong>.</li><li>Move the token — the 3D model follows. Flat on a table, the Z accel axis reads ≈ +1.00 g. Drag the model to orbit the camera.</li><li><strong>LED</strong> toggles the green LED; <strong>Reset</strong> re-zeros the heading (yaw) only, so tilt stays gravity-levelled. The <strong>rate</strong> button steps the IMU sample rate (0.25× = 26 Hz … 4× = 416 Hz; 1× = 104 Hz), and the dropdown switches the 3D model.</li></ol><h2 id="protocol-mapping" tabindex="-1">Protocol mapping <a class="header-anchor" href="#protocol-mapping" aria-label="Permalink to &quot;Protocol mapping&quot;">​</a></h2><p>See the <a href="./ble-protocol">BLE protocol</a> and <a href="./imu-streaming">IMU streaming</a> pages for the authoritative spec; the page mirrors it:</p><table tabindex="0"><thead><tr><th>Item</th><th>Value</th></tr></thead><tbody><tr><td>Service (NUS)</td><td><code>6e400001-b5a3-f393-e0a9-e50e24dcca9e</code></td></tr><tr><td>RX (write)</td><td><code>6e400002-…</code> — start command (the LED is on <code>…0004</code>, not here)</td></tr><tr><td>TX (notify)</td><td><code>6e400003-…</code> — 14-byte IMU frames</td></tr><tr><td>Control (LED)</td><td><code>6e400004-…</code> — 1-bit: <code>0x01</code> on / <code>0x00</code> off</td></tr><tr><td>Start command</td><td><code>20 10 00 D0 07 68 00 03</code> (write to RX)</td></tr><tr><td>Frame</td><td><code>22 00 | gyroX gyroY gyroZ | accelX accelY accelZ</code></td></tr><tr><td>Each axis</td><td>signed int16, little-endian</td></tr><tr><td>Scales</td><td>gyro / 14.286 (°/s), accel / 2048.0 (g)</td></tr></tbody></table><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><strong>Yaw drifts</strong> over time: 6-axis fusion has no magnetometer, so heading is relative — use <em>Reset</em> to re-zero it.</li><li>The browser <strong>cannot emit a real joystick / HID gamepad</strong>; this page is a visualizer. A true controller bridge (joystick / OSC / HID) needs a native helper or a WebSocket/WebHID side channel.</li></ul>`,22)])])}const u=t(s,[["render",i]]);export{g as __pageData,u as default};
